# Terraform: 転送中の暗号化が強制された MSK クラスター
resource "aws_msk_cluster" "<example_resource_name>" {
  cluster_name           = "<example_resource_name>"
  kafka_version          = "<VERSION>"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    client_subnets = [
      "subnet-<example_resource_id>",
      "subnet-<example_resource_id>",
    ]
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"  # 重要: クライアント-ブローカー TLS のみを強制します
      in_cluster    = true    # 重要: ブローカー間暗号化を有効にします
    }
  }
}
```
